mapper.select:
SELECT r.*, s.source_name, s.source_url, u.username FROM data_fetch_record r LEFT JOIN data_source s ON r.source_id = s.id LEFT JOIN sys_user u ON r.user_id = u.id WHERE 1=1
AND r.user_id = #{userId}
AND r.source_id = #{sourceId}
AND r.city LIKE CONCAT('%', #{city}, '%')
ORDER BY r.create_time DESC
